class Solution {
    public String maximumBinaryString(String binary) {
        int zeros = 0;
        for (char c : binary.toCharArray()) {
            if (c == '0') {
                zeros++;
            }
        }
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < zeros - 1; i++) {
            sb.append("1");
        }
        for (int i = 0; i < binary.length() - zeros + 1; i++) {
            sb.append("0");
        }
        return sb.toString();
    }
}
